class Solution:
    def numOfWays(self, n: int) -> int:
        MOD = 10**9 + 7
        # Enumerate all valid first rows then simulate
        from itertools import product
        def valid_row(r):
            return r[0] != r[1] and r[1] != r[2]
        def compatible(r1, r2):
            return all(a != b for a, b in zip(r1, r2))
        rows = [r for r in product(range(3), repeat=3) if valid_row(r)]
        prev = {r: 1 for r in rows}
        for _ in range(n - 1):
            curr = {r: 0 for r in rows}
            for r1 in rows:
                for r2 in rows:
                    if compatible(r1, r2):
                        curr[r2] = (curr[r2] + prev[r1]) % MOD
            prev = curr
        return sum(prev.values()) % MOD

