class Solution:
    def numOfWays(self, n: int) -> int:
        MOD = 10**9 + 7
        # type121: a-b-a patterns, type123: a-b-c patterns
        # Initial count for n=1: 3*2=6 type121, 3*2*1=6 type123
        t121, t123 = 6, 6
        for _ in range(n - 1):
            t121, t123 = (3 * t121 + 2 * t123) % MOD, (2 * t121 + 2 * t123) % MOD
        return (t121 + t123) % MOD

