var numOfWays = function(n) {
    const MOD = BigInt(10**9 + 7);
    let t121 = 6n, t123 = 6n;
    for (let i = 1; i < n; i++) {
        [t121, t123] = [(3n * t121 + 2n * t123) % MOD, (2n * t121 + 2n * t123) % MOD];
    }
    return Number((t121 + t123) % MOD);
};
